import argparse
import json
import pickle
from pathlib import Path
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist"}

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))  # round to avoid float precision issues
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", (0.0, 0.0)))
    # Find closest current node if exact match missing
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    # Build graph
    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = neighs
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def graph_distance(start, goal):
        if start == goal:
            return 0
        queue = deque([(start, 0)])
        seen = {start}
        while queue:
            curr, dist = queue.popleft()
            for neigh in graph.get(curr, []):
                if neigh not in seen:
                    if neigh == goal:
                        return dist + 1
                    seen.add(neigh)
                    queue.append((neigh, dist + 1))
        return float('inf')

    # Select best target by utility / (dist + 1)
    best_score = -1.0
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = graph_distance(current_pos, tcoord)
        if dist == float('inf') or dist == 0:
            continue
        score = util / (dist + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        # fallback: max utility neighbor
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Find next node on shortest path to best_target
    def find_next_on_path(start, goal):
        if start == goal:
            return start
        queue = deque([start])
        parent = {start: None}
        while queue:
            curr = queue.popleft()
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                if neigh not in parent:
                    parent[neigh] = curr
                    queue.append(neigh)
        if goal not in parent:
            return None
        # Trace back to find child of start
        curr = goal
        while parent.get(curr) != start and parent.get(curr) is not None:
            curr = parent[curr]
        return curr

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        # fallback to local max utility
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Return the matching neighbor object (list or tuple as provided by env)
    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    eval_config_path = data_path / "eval_config.json"
    maps = []
    if eval_config_path.exists():
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        maps = config.get("maps", [])
    if not maps:
        # fallback discovery
        for typ in ["room", "tunnel", "outdoor"]:
            map_dir = data_path / "maps_eval" / typ
            if map_dir.exists():
                for mf in sorted(map_dir.glob("*.png")):
                    maps.append(str(mf.relative_to(data_path)))
            else:
                # try maps_train as proxy for local testing
                map_dir = data_path / "maps_train" / typ
                if map_dir.exists():
                    for mf in sorted(map_dir.glob("*.png"))[:5]:  # limit for speed
                        maps.append(str(mf.relative_to(data_path)))
    if not maps:
        print("No maps found.")
        return

    results = []
    type_stats = {"room": {"explored": [], "dist": [], "succ": []},
                  "tunnel": {"explored": [], "dist": [], "succ": []},
                  "outdoor": {"explored": [], "dist": [], "succ": []}}
    for map_rel in maps:
        map_path = data_path / map_rel
        if not map_path.exists():
            alt_path = data_path / "maps_eval" / map_rel
            if alt_path.exists():
                map_path = alt_path
            else:
                print(f"Map not found: {map_rel}")
                continue
        env = ExplorationEnv(map_path=str(map_path))
        obs = env.reset()
        step = 0
        max_steps = 128
        while step < max_steps:
            target = select_waypoint(obs, model)
            if target is None:
                break
            obs, info = env.step(target)
            step += 1
            if info.get("done", False):
                break
        metrics = env.get_metrics()
        explored_rate = metrics.get("explored_rate", 0.0)
        travel_distance = metrics.get("travel_distance", 0.0)
        success = 1 if explored_rate > 0.9999 else 0
        map_rel_str = str(map_rel)
        if map_rel_str.startswith("maps_eval/"):
            map_rel_str = map_rel_str[len("maps_eval/"):]
        elif map_rel_str.startswith("maps_train/"):
            map_rel_str = map_rel_str[len("maps_train/"):]
        env_type = Path(map_rel_str).parts[0]
        res = {
            "map_path": map_rel_str,
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        }
        results.append(res)
        if env_type in type_stats:
            type_stats[env_type]["explored"].append(explored_rate)
            type_stats[env_type]["succ"].append(success)
            if success:
                type_stats[env_type]["dist"].append(travel_distance)

    explored_rates = [r["explored_rate"] for r in results]
    success_rates = [r["success"] for r in results]
    travel_dists = [r["travel_distance"] for r in results if r["success"] == 1]
    mean_explored = float(np.mean(explored_rates)) if explored_rates else 0.0
    mean_travel = float(np.mean(travel_dists)) if travel_dists else 0.0
    mean_success = float(np.mean(success_rates)) if success_rates else 0.0
    per_type = {}
    for t, stats in type_stats.items():
        if stats["explored"]:
            succ_dists = stats["dist"]
            per_type[t] = {
                "explored_rate": float(np.mean(stats["explored"])),
                "travel_distance": float(np.mean(succ_dists)) if succ_dists else 0.0,
                "success_rate": float(np.mean(stats["succ"]))
            }
    output_data = {
        "explored_rate": mean_explored,
        "travel_distance": mean_travel,
        "success_rate": mean_success,
        "per_episode": results,
        "per_type": per_type,
        "total_episodes": len(results)
    }
    with open(output_path, "w") as f:
        json.dump(output_data, f, indent=2)
    print("Summary:")
    print(f"Total episodes: {len(results)}")
    print(f"Success rate: {mean_success}")
    print(f"Mean explored_rate: {mean_explored}")
    print(f"Mean travel_distance (success): {mean_travel}")
    print(f"Per type: {per_type}")

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)

if __name__ == "__main__":
    main()
